require("dotenv").config({ path: require("path").resolve(__dirname, "../.env") });
const ftp = require("basic-ftp");
const path = require("path");
const fs = require("fs");
const os = require("os");

function buildPhpConfig() {
    return `<?php
// Production config — auto-generated by deploy-production.js
// Stored outside webroot: yutopias.com/private/newsletter-config.php
return [
    "db_host"     => "${process.env.PROD_DB_HOST}",
    "db_port"     => ${process.env.PROD_DB_PORT || 3306},
    "db_name"     => "${process.env.PROD_DB_NAME}",
    "db_user"     => "${process.env.PROD_DB_USER}",
    "db_password" => "${process.env.PROD_DB_PASSWORD}",
    "ip_salt"     => "${process.env.PROD_IP_SALT}",
    "notify_to"   => "${process.env.NEWSLETTER_NOTIFY_TO}",
    "mail_from"   => "${process.env.NEWSLETTER_MAIL_FROM}",
];
`;
}

// Safely create or enter a directory (ignores "already exists" errors)
async function safeEnsureDir(client, name) {
    try {
        await client.send("MKD " + name);
    } catch (_) { /* already exists — fine */ }
    await client.cd(name);
}

// Upload directory contents recursively, skipping reserved server dirs
async function uploadDir(client, localDir, skip = new Set()) {
    const entries = fs.readdirSync(localDir, { withFileTypes: true });
    for (const entry of entries) {
        if (skip.has(entry.name)) continue;
        if (entry.isDirectory()) {
            await safeEnsureDir(client, entry.name);
            await uploadDir(client, path.join(localDir, entry.name));
            await client.cd("..");
        } else {
            await client.uploadFrom(path.join(localDir, entry.name), entry.name);
        }
    }
}

async function deploy() {
    const client = new ftp.Client();
    client.ftp.verbose = false;

    const tmpConfig = path.join(os.tmpdir(), "newsletter-config.php");
    fs.writeFileSync(tmpConfig, buildPhpConfig());

    try {
        console.log("🚀 Conectando al servidor FTP (PRODUCCIÓN yutopias.com)...");
        await client.access({
            host: process.env.DEPLOY_HOST,
            user: process.env.DEPLOY_USER,
            password: process.env.DEPLOY_PASSWORD,
            secure: true,
            secureOptions: { rejectUnauthorized: false },
        });
        console.log("✓ Conectado\n");

        // 1. Upload PHP config outside webroot
        // FTP root IS yutopias.com docroot parent — config goes at /private/ (one level above /httpdocs/)
        console.log("📁 Subiendo config PHP fuera del webroot...");
        await client.cd("/");
        await safeEnsureDir(client, "private");
        await client.uploadFrom(tmpConfig, "newsletter-config.php");
        console.log("  ✓ /private/newsletter-config.php\n");

        // 2. Upload static build (skip api/ — uploaded separately as real PHP)
        console.log("📦 Subiendo build estático...");
        await client.cd("/");
        await safeEnsureDir(client, "httpdocs");
        await uploadDir(client, path.join(__dirname, "../out"), new Set(["api"]));
        console.log("  ✓ build estático subido\n");

        // 3. Upload real PHP API files
        console.log("🔌 Subiendo API PHP...");
        await client.cd("/httpdocs");
        await safeEnsureDir(client, "api");
        const phpFiles = ["diagnostic.php", "newsletter.php", "bootcamp-lead.php"];
        for (const f of phpFiles) {
            await client.uploadFrom(path.join(__dirname, "../public/api", f), f);
            console.log("  ✓ api/" + f);
        }

        console.log("\n✅ ¡Despliegue a PRODUCCIÓN finalizado con éxito!");
        console.log("   🌐 https://yutopias.com");

    } catch (err) {
        console.error("\n❌ Error:", err.message);
        console.error(err);
    } finally {
        fs.unlinkSync(tmpConfig);
        client.close();
    }
}

deploy();
